namespace sv_b923c2503fcd4a4facf977968e0424cb.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_b923c2503fcd4a4facf977968e0424cb.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                <span class="channel-desc">@Truncate(channel.Description, 40)</span>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@using sv_b923c2503fcd4a4facf977968e0424cb.Services

<div class="message-item" @onmouseenter="() => _hovered = true" @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    <span>@reaction.Emoji</span>
                    <span class="reaction-count">@reaction.Users.Count</span>
                </button>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadReplyCount replies
        </button>
    }

    @if (_hovered)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">💬</button>
            <button class="action-btn" title="React" @onclick="ToggleEmojiPicker">😀</button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in _commonEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ThreadReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private void OnMouseLeave()
    {
        _hovered = false;
        _showEmojiPicker = false;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@using sv_b923c2503fcd4a4facf977968e0424cb.Services

<div class="message-area">
    <div class="message-area-header">
        <h2># @Channel.Name</h2>
        <p>@Channel.Description</p>
    </div>

    <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
        @if (_loadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageItem Message="msg"
                         ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <div class="message-input-area">
        <textarea @bind="NewMessageText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Message #@Channel.Name" rows="2"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(NewMessageText)">Send</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }

    private string NewMessageText { get; set; } = "";
    private ElementReference _messageListRef;
    private bool _loadingMore;

    private int GetThreadReplyCount(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId)?.ReplyCount ?? 0;

    private async Task HandleScroll()
    {
        // Scroll-to-top pagination is handled via JS interop in production.
        // Here we expose the OnLoadMore callback for the parent to wire up.
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(NewMessageText)) return;
        var text = NewMessageText;
        NewMessageText = "";
        await OnSendMessage.InvokeAsync(text);
    }

    public async Task LoadMoreIfScrolledToTop()
    {
        if (!HasMoreMessages || _loadingMore) return;
        _loadingMore = true;
        StateHasChanged();
        await OnLoadMore.InvokeAsync();
        _loadingMore = false;
        StateHasChanged();
    }
}

@using sv_b923c2503fcd4a4facf977968e0424cb.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="message-author">@RootMessage.Author</span>
            <p class="message-content">@RootMessage.Content</p>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <div class="thread-input-area">
            <textarea @bind="ReplyText" @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Reply…" rows="2"></textarea>
            <button class="send-btn" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(ReplyText)">Reply</button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private string ReplyText { get; set; } = "";

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendReply();
        }
    }

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(ReplyText)) return;
        var text = ReplyText;
        ReplyText = "";
        await OnSendReply.InvokeAsync(text);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

