@using sv_b923c2503fcd4a4facf977968e0424cb.Services

<div class="message-area">
    <div class="message-area-header">
        <h2># @Channel.Name</h2>
        <p>@Channel.Description</p>
    </div>

    <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
        @if (_loadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageItem Message="msg"
                         ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <div class="message-input-area">
        <textarea @bind="NewMessageText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Message #@Channel.Name" rows="2"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(NewMessageText)">Send</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }

    private string NewMessageText { get; set; } = "";
    private ElementReference _messageListRef;
    private bool _loadingMore;

    private int GetThreadReplyCount(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId)?.ReplyCount ?? 0;

    private async Task HandleScroll()
    {
        // Scroll-to-top pagination is handled via JS interop in production.
        // Here we expose the OnLoadMore callback for the parent to wire up.
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(NewMessageText)) return;
        var text = NewMessageText;
        NewMessageText = "";
        await OnSendMessage.InvokeAsync(text);
    }

    public async Task LoadMoreIfScrolledToTop()
    {
        if (!HasMoreMessages || _loadingMore) return;
        _loadingMore = true;
        StateHasChanged();
        await OnLoadMore.InvokeAsync();
        _loadingMore = false;
        StateHasChanged();
    }
}

