@page "/chat"
@rendermode InteractiveServer
@using sv_b923c2503fcd4a4facf977968e0424cb.Services
@using sv_b923c2503fcd4a4facf977968e0424cb.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannelId"
                    OnChannelSelected="SelectChannel" />

    @if (_activeChannel is not null)
    {
        <div class="main-and-thread @(_threadOpen ? "thread-open" : "")">
            <MessageArea Channel="_activeChannel"
                         Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         HasMoreMessages="_hasMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadMore="LoadMoreMessages" />

            @if (_threadOpen)
            {
                <ThreadPanel RootMessage="_threadRootMessage"
                             Replies="_threadReplies"
                             OnClose="CloseThread"
                             OnSendReply="SendThreadReply" />
            }
        </div>
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private Channel? _activeChannel;
    private int _activeChannelId;
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];
    private bool _hasMoreMessages = true;
    private const int PageSize = 50;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _threadSummaries = [];
        _hasMoreMessages = true;
        CloseThreadInternal();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _hasMoreMessages = messages.Count == PageSize;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        // Refresh channel list to update unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (_activeChannel is null || !_hasMoreMessages) return;

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);
        _hasMoreMessages = older.Count == PageSize;
        _messages.InsertRange(0, older);
        BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;

        var message = await ChatService.SendMessageAsync(_activeChannel.Id, content, null);
        _messages.Add(message);
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        CloseThreadInternal();
    }

    private void CloseThreadInternal()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannel is null || _threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update thread summary count
        BuildThreadSummaries();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        if (_activeChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _messages.Count);
        }
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from messages that have replies referencing them
        var replyGroups = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        _threadSummaries = replyGroups
            .Select(g => new ThreadSummary(
                g.Key,
                g.Count(),
                g.Max(m => m.SentAt)))
            .ToList();
    }
}

/* ===== Layout ===== */
