toolArgs.file_text:
/* ===== Layout ===== */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
}

.main-and-thread {
    display: flex;
    flex: 1;
    min-width: 0;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #616061;
    font-size: 1.1rem;
}

/* ===== Channel Sidebar ===== */
::deep .channel-sidebar {
    width: 260px;
    min-width: 220px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow-y: auto;
}

::deep .sidebar-header {
    padding: 16px 16px 8px;
}

::deep .sidebar-header h3 {
    color: #fff;
    font-size: 1.1rem;
    margin: 0;
}

::deep .channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

::deep .channel-item {
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 8px;
    transition: background 0.15s;
}

::deep .channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

::deep .channel-item.active {
    background: #1264a3;
    color: #fff;
}

::deep .channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .channel-desc {
    font-size: 0.75rem;
    opacity: 0.7;
    display: block;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ===== Message Area ===== */
::deep .message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    border-right: 1px solid #e1e1e1;
}

::deep .message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e1e1e1;
    background: #fff;
}

::deep .message-area-header h2 {
    margin: 0;
    font-size: 1.15rem;
}

::deep .message-area-header p {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #616061;
}

::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

::deep .loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

/* ===== Message Item ===== */
::deep .message-item {
    position: relative;
    padding: 6px 20px;
    transition: background 0.1s;
}

::deep .message-item:hover {
    background: #f8f8f8;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .message-author {
    font-weight: 700;
    font-size: 0.95rem;
}

::deep .message-time {
    font-size: 0.75rem;
    color: #999;
}

::deep .message-content {
    font-size: 0.95rem;
    line-height: 1.5;
    word-break: break-word;
}

::deep .reaction-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

::deep .reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border-radius: 12px;
    border: 1px solid #e1e1e1;
    background: #f0f0f0;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.1s;
}

::deep .reaction-badge:hover {
    background: #d9eaf7;
    border-color: #1264a3;
}

::deep .reaction-count {
    font-size: 0.75rem;
    font-weight: 600;
}

::deep .thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0 0;
    display: block;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

::deep .message-actions {
    position: absolute;
    top: -8px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e1e1e1;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    padding: 2px;
    z-index: 10;
}

::deep .action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 1rem;
}

::deep .action-btn:hover {
    background: #f0f0f0;
}

::deep .emoji-picker {
    position: absolute;
    top: -8px;
    right: 90px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e1e1e1;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    padding: 6px;
    z-index: 11;
}

::deep .emoji-btn {
    background: none;
    border: none;
    font-size: 1.25rem;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
}

::deep .emoji-btn:hover {
    background: #f0f0f0;
}

/* ===== Message Input ===== */
::deep .message-input-area,
::deep .thread-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e1e1e1;
    background: #fff;
}

::deep .message-input-area textarea,
::deep .thread-input-area textarea {
    flex: 1;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.95rem;
    resize: none;
    font-family: inherit;
}

::deep .message-input-area textarea:focus,
::deep .thread-input-area textarea:focus {
    outline: none;
    border-color: #1264a3;
    box-shadow: 0 0 0 2px rgba(18, 100, 163, 0.2);
}

::deep .send-btn {
    padding: 8px 20px;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    white-space: nowrap;
}

::deep .send-btn:hover:not(:disabled) {
    background: #006549;
}

::deep .send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ===== Thread Panel ===== */
::deep .thread-panel {
    width: 340px;
    min-width: 280px;
    border-left: 1px solid #e1e1e1;
    display: flex;
    flex-direction: column;
    background: #fff;
}

::deep .thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e1e1e1;
}

::deep .thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
}

::deep .close-btn {
    background: none;
    border: none;
    font-size: 1.25rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

::deep .close-btn:hover {
    background: #f0f0f0;
}

::deep .thread-root-message {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e1e1e1;
}

::deep .thread-root-message .message-author {
    font-weight: 700;
    font-size: 0.9rem;
}

::deep .thread-root-message .message-content {
    font-size: 0.9rem;
    margin-top: 4px;
    color: #555;
}

::deep .thread-divider {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #888;
    border-bottom: 1px solid #e1e1e1;
}

::deep .thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

::deep .thread-reply {
    padding: 8px 16px;
}

::deep .thread-reply .message-author {
    font-size: 0.85rem;
}

::deep .thread-reply .message-content {
    font-size: 0.9rem;
}

